mapper.select:
select wg.id, wg.category_id, wg.room_id, wg.gen_time, wg.gen_qty, wg.remain_qty, wg.temp_operator, wg.temp_operator_out_name, wg.temp_operator_out_phone, wg.tran_operator, wg.tran_operator_out_name, wg.tran_operator_out_phone, wg.day_seq, wg.batch_no, wg.manual_batch_no, wg.remark, c.waste_name, c.waste_dict_id, r.room_name from t_waste_generate wg left join t_waste_category c on c.category_id = wg.category_id left join t_waste_room r on r.room_id = wg.room_id
and c.ent_code in
#{entCode}
and wg.category_id = #{categoryId}
and wg.gen_time between #{startTime} and #{endTime}
and wg.remain_qty > 0
order by wg.id desc

select wr.id, wr.category_id, wr.room_id, wr.reduction_time, wr.reduction_qty, wr.duration, wr.method, wr.operator, wr.operator_out_name, wr.operator_out_phone, wr.day_seq, wr.batch_no, wr.manual_batch_no, wr.remark, c.waste_name, c.waste_dict_id, r.room_name from t_waste_reduction wr left join t_waste_category c on c.category_id = wr.category_id left join t_waste_room r on r.room_id = wr.room_id
and c.ent_code in
#{entCode}
and wr.category_id = #{categoryId}
and wr.reduction_time between #{startTime} and #{endTime}
order by wr.id desc

select ws.id, ws.category_id, ws.room_id, ws.storage_time, ws.storage_qty, ws.remain_qty, ws.storage_operator, ws.storage_operator_out_name, ws.storage_operator_out_phone, ws.tran_operator, ws.tran_operator_out_name, ws.tran_operator_out_phone, ws.day_seq, ws.batch_no, ws.manual_batch_no, ws.remark, c.waste_name, c.waste_dict_id, r.room_name from t_waste_storage ws left join t_waste_category c on c.category_id = ws.category_id left join t_waste_room r on r.room_id = ws.room_id
and c.ent_code in
#{entCode}
and ws.category_id = #{categoryId}
and ws.storage_time between #{startTime} and #{endTime}
and ws.remain_qty > 0
order by ws.id desc

select wo.id, wo.out_type, wo.category_id, wo.out_time, wo.out_qty, wo.out_operator, wo.out_operator_out_name, wo.out_operator_out_phone, wo.tran_operator, wo.tran_operator_out_name, wo.tran_operator_out_phone, wo.tran_unit, wo.vehicle_no, wo.disposal_unit, wo.day_seq, wo.batch_no, wo.manual_batch_no, wo.remark, c.waste_name, c.waste_dict_id from t_waste_outbound wo left join t_waste_category c on c.category_id = wo.category_id
and c.ent_code in
#{entCode}
and wo.category_id = #{categoryId}
and wo.out_time between #{startTime} and #{endTime}
order by wo.id desc

select count(*)
from t_waste_flow_rel
where
    flow_type in

            #{item}

    and source_id = #{sourceId}

mapper.delete:
delete from t_waste_flow_rel
where
    flow_type in

            #{item}

    and target_id = #{targetId}

mapper.update:
update t_waste_generate g inner join t_waste_flow_rel f on f.flow_type in
#{item}
and f.source_id = g.id and f.target_id = #{targetId} set g.remain_qty = g.gen_qty - ( select COALESCE(sum(qty), 0) from t_waste_flow_rel where flow_type in
#{item}
and source_id = g.id )

update
    t_waste_storage s
    inner join t_waste_flow_rel f on
        f.flow_type = #{flowType}
        and f.source_id = s.id
        and f.target_id = #{targetId}
set s.remain_qty = s.storage_qty - (
    select COALESCE(sum(qty), 0)
    from t_waste_flow_rel
    where
        flow_type = #{flowType}
        and source_id = s.id
)
